import React from "react"
import '../styles/MainStyles.css';
import { useState } from 'react';



export function SignUp(){
    const [userName, setName] = useState('')

    const [login, setLogin] = useState('')

    const [pass, setPass] = useState('')

    const [confirmPass, setConfirm] = useState('')

    const changePass = (event) =>{
        setPass(event.target.value)
    }

    const changeLogin = (event) =>{
        setLogin(event.target.value)
    }

    const changeName = (event) =>{
        setName(event.target.value)
    }

    const changeConfirm = (event) =>{
        setConfirm(event.target.value)
    }

    return(
        <div className="formsign">
            <div className="titleform">
                Регистрация
            </div>
            <div className="input-group">
                      <input type="text" className="input-field" placeholder="Введите имя" value={login} onChange={changeName}/>
                      <input type="text" className="input-field" placeholder="Логин или Email" value={login} onChange={changeLogin}/>
                      <input type="text" className="input-field" placeholder="Пароль" value={pass} onChange={changePass}/>
                      <input type="text" className="input-field" placeholder="Повторите пароль" value={pass} onChange={changeConfirm}/>
                      <button class="button-style">Войти</button>
            </div>
                   <div className="registNav">
                   <span>Уже есть аккаунт? </span>
                   <a 
                     href="/"
                    className="create-account-link"
                    onClick={(e) => {
                    }}>
                       Войти
                   </a>
            </div>
        </div>
    )
}
